import "server-only";

import NextAuth from "next-auth";
import Credentials from "next-auth/providers/credentials";

import { authConfig } from "@/auth.config";
import { env } from "@/lib/config/env";
import { DEMO_USER_ID } from "@/lib/auth/roles";
import { verifyPassword } from "@/lib/auth/password";
import { prisma } from "@/lib/prisma";

export const { handlers, signIn, signOut, auth } = NextAuth({
  ...authConfig,
  secret: env.authSecret,
  providers: [
    Credentials({
      credentials: {
        username: {
          label: "Username",
          type: "text"
        },
        password: {
          label: "Password",
          type: "password"
        }
      },
      async authorize(credentials) {
        const username = String(credentials?.username ?? "");
        const password = String(credentials?.password ?? "");

        if (!username || !password) {
          return null;
        }

        if (env.demoCredentials && username === env.demoCredentials.username && password === env.demoCredentials.password) {
          return {
            id: DEMO_USER_ID,
            name: username,
            role: "demo"
          };
        }

        const owner = await prisma.user.findUnique({ where: { username } });

        if (!owner || !verifyPassword(password, owner.passwordHash)) {
          return null;
        }

        return {
          id: owner.id,
          name: owner.username,
          role: "owner"
        };
      }
    })
  ],
  callbacks: {
    ...authConfig.callbacks,
    jwt({ token, user }) {
      if (user) {
        token.sub = user.id;
        token.name = user.name;
        token.role = user.role;
      }

      return token;
    },
    session({ session, token }) {
      if (session.user && token.sub) {
        session.user.id = token.sub;
        session.user.name = token.name ?? session.user.name;
        session.user.role = token.role === "demo" ? "demo" : "owner";
      }

      return session;
    }
  }
});

import "server-only";

import { redirect } from "next/navigation";

import { auth } from "@/auth";
import { env } from "@/lib/config/env";
import { prisma } from "@/lib/prisma";
import type { WorkspaceRole } from "./roles";

export async function getOwnerSession() {
  const session = await getWorkspaceSession();

  if (!session || session.actor.role !== "owner") {
    return null;
  }

  return {
    id: session.owner.id,
    name: session.owner.name,
    role: session.actor.role
  };
}

export async function getWorkspaceSession() {
  const session = await auth();

  if (!session?.user?.id || !session.user.role) {
    return null;
  }

  const ownerLookup = session.user.role === "owner" ? { id: session.user.id } : { username: env.ownerUsername };
  const owner = await prisma.user.findUnique({
    where: {
      ...ownerLookup
    },
    select: {
      id: true,
      username: true
    }
  });

  if (!owner) {
    return null;
  }

  return {
    actor: {
      id: session.user.id,
      name: session.user.name ?? owner.username,
      role: session.user.role as WorkspaceRole
    },
    owner: {
      id: owner.id,
      name: owner.username
    }
  };
}

export async function requireOwnerSession() {
  const session = await getOwnerSession();

  if (!session) {
    redirect("/login");
  }

  return session;
}

export async function requireWorkspaceSession() {
  const session = await getWorkspaceSession();

  if (!session) {
    redirect("/login");
  }

  return session;
}

"use server";

import { AuthError } from "next-auth";
import { redirect } from "next/navigation";

import { signIn } from "@/auth";

export async function loginAction(formData: FormData) {
  const username = String(formData.get("username") ?? "");
  const password = String(formData.get("password") ?? "");

  try {
    await signIn("credentials", {
      username,
      password,
      redirectTo: "/app"
    });
  } catch (error) {
    if (error instanceof AuthError) {
      redirect("/login?error=CredentialsSignin");
    }

    throw error;
  }
}

