                        <Button type="submit">Publish link</Button>
                      </form>
                    )}
                  </div>
                  {link.enrichment.status === "failed" ? (
                    <form action={retryLinkEnrichmentAction.bind(null, link.id)} className="secondary-link-retry">
                      <Button type="submit" variant="ghost">
                        Retry AI enrichment
